/**
 * @summary List legislations for an organization
 */
export const getListLegislationsUrl = (
  orgId: number,
  params?: ListLegislationsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/organizations/${orgId}/legislations?${stringifiedParams}`
    : `/api/organizations/${orgId}/legislations`;
};

